// ================== 1. INPUT DATA ==================
const data = items.map(item => item.json);

// ================== 2. DATA CLEANING ==================
const cleaned = data.map(row => {
    let obj = {};
    for (let key in row) {
        let val = row[key];

        // Handle missing values
        if (val === null || val === undefined || val === "") {
            val = 0;
        }

        // Convert to number if possible
        if (!isNaN(val)) {
            val = Number(val);
        }

        obj[key.trim()] = val;
    }
    return obj;
});

// ================== 3. METRICS ==================
const keys = Object.keys(cleaned[0] || {});
const numKeys = keys.filter(k => typeof cleaned[0][k] === "number");

let metrics = {};

numKeys.forEach(k => {
    let vals = cleaned.map(r => r[k]);
    let sum = vals.reduce((a, b) => a + b, 0);

    metrics[k] = {
        sum: sum,
        avg: sum / vals.length,
        max: Math.max(...vals),
        min: Math.min(...vals)
    };
});

// ================== 4. CHART DATA ==================
const labels = cleaned.map((_, i) => `Row ${i + 1}`);
const values = cleaned.map(r => r[numKeys[0]] || 0);

// ================== 5. QUICKCHART URL ==================
const chartConfig = {
    type: "bar",
    data: {
        labels: labels.slice(0, 10),
        datasets: [{
            label: numKeys[0],
            data: values.slice(0, 10)
        }]
    }
};

const chartUrl = "https://quickchart.io/chart?c=" + encodeURIComponent(JSON.stringify(chartConfig));

// ================== 6. INTRO TEXT ==================
let introText = `
<p>Dear Consumer,</p>

<p>
We have analyzed the provided dataset, performed data cleaning and preprocessing,
and generated meaningful visualizations based on the analysis requirements.
The insights derived from the data are presented below for your review.
</p>
`;

// ================== 7. REPORT HTML ==================
let reportHtml = introText + `
<h2>📊 Summary Metrics</h2>

<table border="1" cellpadding="6" cellspacing="0">
<tr>
    <th>Column</th>
    <th>Sum</th>
    <th>Average</th>
    <th>Max</th>
    <th>Min</th>
</tr>
`;

for (let k in metrics) {
    reportHtml += `
    <tr>
        <td>${k}</td>
        <td>${metrics[k].sum}</td>
        <td>${metrics[k].avg.toFixed(2)}</td>
        <td>${metrics[k].max}</td>
        <td>${metrics[k].min}</td>
    </tr>`;
}

reportHtml += `
</table>

<h2>📈 Data Visualization</h2>
<p>Below is the graphical representation of the dataset:</p>

<img src="${chartUrl}" />

<br><br>

<p>Best regards,<br>
Data Analytics System</p>
`;

// ================== 8. EMAIL HTML ==================
const emailHtml = `
<p>Dear Consumer,</p>

<p>Your data report has been generated successfully.</p>

<img src="${chartUrl}" />

<p>Detailed report is provided below:</p>

${reportHtml}

<p>Regards,<br>
Automation System</p>
`;

// ================== 9. RETURN ==================
return [
    {
        json: {
            cleanedData: cleaned,
            metrics: metrics,
            chartUrl: chartUrl,
            reportHtml: reportHtml,
            emailHtml: emailHtml
        }
    }
];
